209→internal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
210→
211→internal open class ConcatenatedFormatStructure<in T>(
212→    val formats: List<NonConcatenatedFormatStructure<T>>
213→) : FormatStructure<T> {
214→    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
215→
216→    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
217→
218→    override fun hashCode(): Int = formats.hashCode()
219→
220→    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
221→
222→    override fun formatter(): FormatterStructure<T> {
223→        val formatters = formats.map { it.formatter() }
224→        return if (formatters.size == 1) {
225→            formatters.single()
226→        } else {
227→            ConcatenatedFormatter(formatters)
228→        }
229→    }
230→}
