package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests that error messages during parsing and formatting include relevant information.
 */
class ErrorMessageFormatTest {
    /**
     * Test that when validation errors occur (like inconsistent AM/PM marker), the input is included.
     */
    @Test
    fun testAmPmInconsistencyShowsInput() {
        val format = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        // 23:30 with AM marker is inconsistent (23 is PM)
        val error = assertFailsWith<DateTimeFormatException> { format.parse("23:30 AM") }
        // The error should contain the input
        assertContains(error.message!!, "23:30 AM", "Error message should contain the full input")
        // The error should mention the inconsistency
        assertContains(error.message!!, "Inconsistent", ignoreCase = true)
    }

    /**
     * Test that when validation errors occur in date parsing, the input is included.
     */
    @Test
    fun testInvalidDateShowsInput() {
        val format = LocalDate.Formats.ISO
        // February 30 is not a valid date
        val error = assertFailsWith<DateTimeFormatException> { format.parse("2020-02-30") }
        // The error should contain the input
        assertContains(error.message!!, "2020-02-30", "Error message should contain the full input")
    }

    /**
     * Test that the "one of" in error messages is lowercase.
     */
    @Test
    fun testExpectedOneOfIsLowercase() {
        val format = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        // "XX" is not a valid AM/PM marker
        val error = assertFailsWith<DateTimeFormatException> { format.parse("12:30 XX") }
        // If the error mentions "one of", it should be lowercase
        // This test will only pass if the message contains "one of" (lowercase)
        // Note: this tests the "Expected one of" error format
        if (error.message!!.contains("one of", ignoreCase = true)) {
            assertContains(error.message!!, "one of", "Error message should use lowercase 'one of'")
        }
    }

    /**
     * Test that UTC offset validation errors show the input.
     */
    @Test
    fun testInvalidUtcOffsetShowsInput() {
        // UTC offset cannot exceed 18 hours
        val format = UtcOffset.Formats.ISO
        val error = assertFailsWith<DateTimeFormatException> { format.parse("+20:00") }
        // The error should contain the input
        assertContains(error.message!!, "+20:00", "Error message should contain the full input")
    }
}
"}

